var e=JSON.parse(`[{"id":"L9_1","type":"dialog","speaker":"POLICE_NPC_FORCE_NULL","text":{"KOREA":"양측 세력 모두 집결 마친 것 같습니다. 핵심간부들도 몇몇 보입니다.","JPN":"両方の勢力とも、集結したようです。核心の幹部も数人見えます。","ENG":"Both families have gathered, sir. I also see a couple of core members in the mix.","TWN":"雙方勢力似乎都已集結完畢。也能看到一些核心幹部。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"POLICE_NPC_FORCE_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L10_1","type":"dialog","speaker":"POLICE_NPC_FORCE_CHIEF","text":{"KOREA":"지시 기다려. 판 벌리기 전까진 대기한다.","JPN":"指示を待て。事が起こるまでは待機する。","ENG":"Wait for my orders. Until then, stay down.","TWN":"等待指示，在行動開始前原地待命。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"POLICE_NPC_FORCE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLICE_NPC_FORCE_CHIEF","face":"UNIT_IDLE"}}}},{"id":"L11_1","type":"dialog","speaker":"POLICE_NPC_FORCE_NULL","text":{"KOREA":"양측에서 한 명씩 앞으로 나오고 있습니다. 말싸움이 벌어지는 듯 합니다.","JPN":"両方から一人ずつ前に出ました。口争いをしているようです。","ENG":"A member from each family is walking towards each other. Looks like they’re entering an argument.","TWN":"雙方各站出一人，似乎是發生口角。"},"stage":{"bg":"VEHICLE","slots":{"L":{"char_id":"POLICE_NPC_FORCE_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"POLICE_NPC_FORCE_CHIEF","face":"UNIT_IDLE"}}}},{"id":"L14_1","type":"dialog","speaker":"BULLY_NPC_TEAM2_LEADER","text":{"KOREA":"너넨 머릿수도 딸리는 주제에 뭘 믿고 기어 나왔대?","JPN":"貴様ら、人数も足りねえくせに何しに来た？","ENG":"Look at you and that pathetic army you call a family.","TWN":"你們人手不足，還敢出來逞強？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_NPC_TEAM2_LEADER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L16_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"싸우는 법도 모르는 풋내기들 잔뜩 모아다 놓고 허세부리긴.","JPN":"戦い方も知らねえ素人でいっぱいなんだろう？　強がるなって。","ENG":"Do you really think your rookies have a chance against my men?","TWN":"一群連打架都不會的菜鳥，還在那裝腔作勢。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"이쪽은 카운터를 데려왔다고.","JPN":"こっちはカウンターを連れてきたんだ。","ENG":"I’ve got a Counter on my side, what about you?","TWN":"我們可帶來了制裁者。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"}}}},{"id":"L19_1","type":"dialog","speaker":"BULLY_NPC_TEAM2_LEADER","text":{"KOREA":"카운터라고? 설마…?","JPN":"カウンターだと？　まさか……？","ENG":"A Counter? No way...","TWN":"制裁者？難道是…？"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_NPC_TEAM2_LEADER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L21_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"언더그라운드의 미친 개, 독구. 이름을 못 들어봤다고 하진 않겠지?","JPN":"アンダーグラウンドの狂った犬、毒狗。名前は確かに聞いてみたはずだ。","ENG":"Have you heard the name, Paine, the Mad Dog of the Underground?","TWN":"地下世界的瘋狗，蒼蠅。你不會沒聽過這個名字吧？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"BULLY_NPC_COUNTER_DOG","text":{"KOREA":"애들 싸움에 끼고 싶진 않은데, 돈을 꽤 받아서 말이지. 당분간 이 친구들 뒤 좀 봐주기로 했다.","JPN":"子どものケンカに関わりたくねえが、結構もらってるんでな。しばらくこいつらの面倒を見てやることになった。","ENG":"I'm not usually one to get involved in childish nonsense, but the pay was too good to pass up.","TWN":"我本不想參與小孩子的扮家家酒，但錢給得蠻多的，所以暫時決定幫這些傢伙撐撐場面。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_COUNTER_DOG","face":"UNIT_IDLE"}}}},{"id":"L26_1","type":"dialog","speaker":"BULLY_NPC_TEAM2_LEADER","text":{"KOREA":"……그렇군.","JPN":"……そうか。","ENG":"...I see.","TWN":"…原來如此。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_NPC_TEAM2_LEADER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"BULLY_NPC_TEAM2_LEADER","text":{"KOREA":"평소라면 모르겠지만, 이번엔 이쪽도 믿는 구석이 있거든.","JPN":"普段ならまだしも、今度はこっちにも頼るところがあんだよ。","ENG":"I would be scared if it weren’t for something I also have up my sleeve.","TWN":"以前的我們可能會嚇到，但這次我們也是有準備的。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_NPC_TEAM2_LEADER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L28_1","type":"dialog","speaker":"BULLY_NPC_TEAM2_LEADER","text":{"KOREA":"어이, 나와라.","JPN":"おい、出て来い。","ENG":"Hey, C’mere.","TWN":"喂，出來吧。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_NPC_TEAM2_LEADER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":null,"text":{"KOREA":"예이- 예이-","JPN":"はいはい。","ENG":"Yeah, yeah...","TWN":"來囉，來囉"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":null}}},{"id":"L31_1","type":"dialog","speaker":"YUMA_FALLEN_NULL_NULL","text":{"KOREA":"……","JPN":"……","ENG":"...","TWN":"…"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_DESPAIR"},"C":null,"R":null}}},{"id":"L33_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"저, 저 녀석은……?!","JPN":"あ、あいつは……！？","ENG":"Wait, isn't she...?!","TWN":"那，那傢伙是…？！"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"YUMA_FALLEN_NULL_NULL","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L35_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"하하하, 난 또 뭔가 했더니.","JPN":"ははは、なんだ。","ENG":"Hah hah hah! Well will you look at that!","TWN":"哈哈哈，我還以為是什麼厲害的傢伙。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"}}}},{"id":"L36_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"고작 인상 좀 사납게 생긴 여자 하나 데려온 거냐?","JPN":"ちょっぴり印象の悪い女一人で、どうしろってんだ？","ENG":"You brought a chick to a man’s fight!","TWN":"你就帶回來一個長得兇神惡煞的女人嗎？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"}}}},{"id":"L39_1","type":"dialog","speaker":"CRIMINAL_NPC_MEMBER_C","text":{"KOREA":"혀, 형님. 저건……","JPN":"あ、兄貴。あれは……","ENG":"B-boss! Th-that’s...","TWN":"老，老大。那個…"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"},"R":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"뭐야? 가만히 있어봐.","JPN":"んだよ？　じっとしてろ。","ENG":"What? Don’t cut me off.","TWN":"吵什麼？閉上嘴。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"},"R":{"char_id":"CRIMINAL_NPC_MEMBER_C","face":"UNIT_IDLE"}}}},{"id":"L42_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"좋아. 한 번 붙어보자고. 우리 와일드카드와 네 녀석들의 와일드카드.","JPN":"いいぜ。やってみようじゃねえか。うちのワイルドカードと、てめえらのワイルドカード。","ENG":"All right then. Let’s see which is stronger.","TWN":"好。那就來較量一場，我們的王牌對你們的王牌。"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"}}}},{"id":"L43_1","type":"dialog","speaker":"BULLY_NPC_TEAM1_LEADER","text":{"KOREA":"한 쪽이 먼저 쓰러질 때까지 치고 받는 거지, 어때?","JPN":"片方が先に倒れるまで戦うんだ、どうだ？","ENG":"Fine. The last one standing is the winner, okay?","TWN":"雙方打到其中一方先倒下為止，怎麼樣？"},"stage":{"bg":"BACKSTREET2","slots":{"L":null,"C":null,"R":{"char_id":"BULLY_NPC_TEAM1_LEADER","face":"UNIT_IDLE"}}}},{"id":"L45_1","type":"dialog","speaker":"BULLY_NPC_TEAM2_LEADER","text":{"KOREA":"흥, 안 될 거 없지.","JPN":"ふん、いいだろ。","ENG":"Hmph! Sounds good to me.","TWN":"哼，當然可以。"},"stage":{"bg":"BACKSTREET2","slots":{"L":{"char_id":"BULLY_NPC_TEAM2_LEADER","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L48_1","type":"dialog","speaker":"POLICE_NPC_FORCE_NULL","text":{"KOREA":"조직에선 처음 보는 인물 두 명이 맨 앞에서 대치하고 있습니다.","JPN":"組織図では確認できていない二人が一番前に出て対峙しています。","ENG":"A one-on-one fight started, sir. Both fighters are ones I’ve never seen before.","TWN":"組織中有兩名從未見過的人物在最前方對峙。"},"stage":{"bg":"VEHICLE","slots":{"L":null,"C":{"char_id":"POLICE_NPC_FORCE_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};